code.C:
#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        uint64_t p;
        scanf("%llu", &p);
        uint64_t count = (p * (p - 1)) * (p * (p - 1) + 1) / 2;
        printf("%llu\n", count % 1000000007);
    }
    return 0;
}

