import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long p = sc.nextLong();
            long count = (p * (p - 1)) * (p * (p - 1) + 1) / 2;
            System.out.println(count % 1000000007);
        }
    }
}

